const nf = new Intl.NumberFormat('ar-EG-u-nu-latn', { maximumFractionDigits: 0 });
const n = (v) => nf.format(Math.round(Number(v) || 0));
const pct = (v) => (v == null ? '—' : Math.round(Number(v)) + '%');
const esc = (s) => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

const rows = (name) => $(name).all().map((i) => i.json).filter((j) => j && Object.keys(j).length);

const depts = rows('Dept Summary');
const opened = rows('Opened Today').length;
const closed = rows('Closed Today').length;
const sales = rows('Sales This Month');

const label = new Intl.DateTimeFormat('ar-EG-u-nu-latn', { timeZone: 'Africa/Cairo', weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }).format(new Date());

const L = ['📊 <b>تقرير Engosoft اليومي</b> — ' + esc(label), ''];

L.push('🎫 <b>التذاكر المفتوحة:</b>');
const byOpen = [...depts].sort((a, b) => (b.open_cnt || 0) - (a.open_cnt || 0));
if (!byOpen.length) {
  L.push('• مفيش بيانات أقسام.');
} else {
  for (const d of byOpen) {
    const bits = [n(d.open_cnt) + ' مفتوح'];
    if (d.unassigned_cnt > 0) bits.push(n(d.unassigned_cnt) + ' غير مُسند');
    if (d.urgent_cnt > 0) bits.push(n(d.urgent_cnt) + ' عاجل');
    if (d.failed_cnt > 0) bits.push(n(d.failed_cnt) + ' SLA متأخر');
    L.push('• <b>' + esc(d.team_name) + '</b>: ' + bits.join(' · '));
  }
}

L.push('', '🟢 <b>النهاردة:</b> اتفتح ' + n(opened) + ' · اتقفل ' + n(closed));

const critical = depts.filter((d) => (d.sla_met_pct != null && d.sla_met_pct < 80) || d.backlog_7p >= 10);
L.push(critical.length
  ? '🔴 <b>محتاج انتباه:</b> ' + critical.map((d) => esc(d.team_name) + ' (SLA ' + pct(d.sla_met_pct) + ')').join('، ')
  : '🔴 <b>محتاج انتباه:</b> مفيش — كل الأقسام في المستوى.');

L.push('', '💰 <b>السيلز (الشهر لحد دلوقتي) — أعلى 5:</b>');
const top = sales.slice(0, 5);
if (!top.length) {
  L.push('• مفيش مبيعات متسجّلة الشهر ده.');
} else {
  top.forEach((p, i) => L.push((i + 1) + '. ' + esc(p.user_name || '—') + ' — ' + n(p.achieved_total) + ' ج (' + n(p.deals_count) + ' صفقة)'));
  const total = sales.reduce((s, p) => s + (Number(p.achieved_total) || 0), 0);
  L.push('<i>الإجمالي: ' + n(total) + ' ج من ' + n(sales.length) + ' فرد</i>');
}

const rated = depts.filter((d) => d.sla_met_pct != null);
if (rated.length) {
  const best = rated.reduce((a, b) => (b.sla_met_pct > a.sla_met_pct ? b : a));
  const worst = rated.reduce((a, b) => (b.sla_met_pct < a.sla_met_pct ? b : a));
  L.push('', '⭐ <b>أحسن قسم:</b> ' + esc(best.team_name) + ' (' + pct(best.sla_met_pct) + ')', '⚠️ <b>أكتر قسم متأخر:</b> ' + esc(worst.team_name) + ' (' + pct(worst.sla_met_pct) + ')');
}

let text = L.join('\n');
if (text.length > 4096) text = text.slice(0, 4076) + '\n…(اتقصّ)';

return [{ json: { text } }];
